    rd.onload = () => { downscaleImage(rd.result, 600, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } state.partPhoto = out; renderOverlay(); }); };
    rd.onerror = () => toast('Could not read that image.');
