/** Turn a customer-search string into prefill: a letterless string → phone, else
 *  split on the first space into first/last (how staff usually type a name). */
function parseCustomerSearch(q) {
  q = (q || '').trim(); if (!q) return {};
  if (/\d/.test(q) && !/[a-zA-Z]/.test(q)) return { phone: q };
  const parts = q.split(/\s+/);
  return parts.length >= 2 ? { firstName: parts[0], lastName: parts.slice(1).join(' ') } : { firstName: q };
}
/* `linkTo` { card:'rentals'|'invoices', recId } — the standing quick-add-link
   contract (Wave 2): the moment the new customer exists it is LINKED to that
   record via the surviving wrappers; existing customers get DRAGGED on instead. */
function openCustomerForm(editId, prefill, linkTo) {
  const c = editId ? IDX.customer.get(editId) : null;
  const f = (k, d) => (c && c[k] != null ? c[k] : ((prefill && prefill[k]) || d || ''));
  openOverlay({ kind: 'newCustomer', error: '', editId: editId || null, linkTo: (!editId && linkTo) || null, draft: {
    firstName: f('firstName'), lastName: f('lastName'), company: f('company'), phone: f('phone'),
    email: f('email'), industry: f('industry'), accountType: f('accountType', 'Non-Business'),
    requiresPO: c ? !!c.requiresPO : undefined, accountNotes: f('accountNotes'), selfie: f('selfie'), signature: f('signature'),
    agreementType: f('agreementType'), agreementSignedAt: f('agreementSignedAt'),
    idNumber: f('idNumber'), netDays: f('netDays'), custom: (c && c.custom) ? { ...c.custom } : {},
  } });
}
// Downscale + JPEG-compress an image data URL so it fits inside one Sheet cell
// (Google caps cells at ~50k chars). cb receives the compressed data URL.
function downscaleImage(dataUrl, maxDim, quality, cb) {
  const img = new Image();
  img.onload = () => {
    let w = img.width, h = img.height; const s = Math.min(1, maxDim / Math.max(w, h));
    w = Math.max(1, Math.round(w * s)); h = Math.max(1, Math.round(h * s));
    const cv = document.createElement('canvas'); cv.width = w; cv.height = h;
    cv.getContext('2d').drawImage(img, 0, 0, w, h);
    cb(cv.toDataURL('image/jpeg', quality));
  };
  img.onerror = () => cb('');
  img.src = dataUrl;
}
const NC_INDUSTRIES = ['Construction', 'Concrete', 'Welding', 'Electrical', 'Plumbing', 'Roofing', 'Painting', 'Landscaping', 'Trucking', 'Industrial', 'Oil & Gas', 'Real Estate', 'Entertainment', 'Agriculture'];
const NC_ACCOUNT_TYPES = ['Non-Business', 'Business', 'Non-Business Member', 'Business Member'];
/** Next sequential customer id (C0001 format), one past the current max. */
function nextCustomerId() {
  const max = DATA.customers.reduce((m, c) => { const n = /^C(\d+)$/.exec(c.customerId || ''); return n ? Math.max(m, +n[1]) : m; }, 0);
  return 'C' + String(max + 1).padStart(4, '0');
}
/* QUICK ADD (Jac 2026-06-12): the moment First + Phone exist, persist the customer
   behind the scenes and flip the popup to edit mode IN PLACE (no render → typing
   focus kept) so the card-on-file can be attached without a separate Save step. */
function quickSaveCustomer(o) {
  if (!o || o.kind !== 'newCustomer' || o.editId) return null;
  const d = o.draft; if (!d.firstName || !d.phone) return null;
  const id = nextCustomerId();
  const c = {
    customerId: id, firstName: d.firstName, lastName: d.lastName, name: `${d.firstName} ${d.lastName}`.trim(),
    company: d.company, phone: d.phone, email: d.email, address: '',
    industry: d.industry, accountType: d.accountType || 'Non-Business', payStatus: 'New Customer',
    requiresPO: !!d.requiresPO, accountNotes: d.accountNotes, stripeId: '', selfie: d.selfie || '', signature: d.signature || '',
    idNumber: d.idNumber || '', netDays: normNetDays(d.netDays), custom: d.custom || {},
    agreementType: d.agreementType || '', agreementSignedAt: d.agreementSignedAt || '',
    interestedCategoryIds: [], activityLog: [], usedSalesStage: 'N/A', membershipStage: 'N/A',
    _digest: { activePct: 0, totalPaid: 0, visits: 0, years: 0, avgFrequencyDays: 0, firstInvoice: '', lastInvoice: '' },
  };
  DATA.customers.push(c); IDX.customer.set(id, c); reindex('customers', c);
  logAction(c, 'Customer quick-added');
  o.editId = id;
  applyCustomerLink(o, id);   // quick-add-link: born from a Quote/invoice slot → linked immediately
  return id;
}
/* Wave 2 quick-add-link: consumes o.linkTo exactly once through the surviving
   wrappers, remembering it in o.linked so the save path can re-anchor the
   linked Quote/invoice instead of the customer. */
function applyCustomerLink(o, customerId) {
  const lt = o && o.linkTo; if (!lt) return null;
  o.linkTo = null;
  const res = lt.card === 'rentals' ? linkCustomerToRental(lt.recId, customerId)
            : lt.card === 'invoices' ? setInvoiceCustomer(lt.recId, customerId) : null;
  if (!res) return null;   // blocked (the wrapper already toasted why) — fall back to a plain create
  o.linked = lt;
  return lt;
}
/* Persist the current onboarding-form draft (fields + signature + selfie + agreement) onto the
   customer record WITHOUT closing the form — used before the card flow so a return loses nothing. */
function ncSyncDraftToCustomer(o) {
  if (!o || o.kind !== 'newCustomer') return;
  ncSyncInputs();
  if (!o.editId) quickSaveCustomer(o);
  const c = o.editId && IDX.customer.get(o.editId); if (!c) return;
  const d = o.draft;
  Object.assign(c, { firstName: d.firstName, lastName: d.lastName, name: `${d.firstName} ${d.lastName}`.trim(),
    company: d.company, phone: d.phone, email: d.email, industry: d.industry, accountType: d.accountType || 'Non-Business',
    requiresPO: !!d.requiresPO, accountNotes: d.accountNotes });   // §7.1b signature/selfie/agreement live on the CARD now — never wiped from the account form
  reindex('customers', c);
}
function saveNewCustomer() {
  const o = state.overlay; if (!o || o.kind !== 'newCustomer') return;
  const root = document.querySelector('.overlay .popup-body'); if (!root) return;
  root.querySelectorAll('[data-f]').forEach((i) => { o.draft[i.dataset.f] = i.value.trim(); });
  o.draft.custom = o.draft.custom || {};
  root.querySelectorAll('[data-cf]').forEach((i) => { o.draft.custom[i.dataset.cf] = i.value.trim(); });
  ncApplyName(o.draft);
  if (!o.draft.firstName) { o.error = 'A name is required (we use it for marketing).'; renderOverlay(); document.querySelector('.overlay [data-f="name"]')?.focus(); return; }
  if (!o.draft.phone) { o.error = 'A phone number is required.'; renderOverlay(); document.querySelector('.overlay [data-f="phone"]')?.focus(); return; }
  if (o.draft.email && !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(o.draft.email)) { o.error = 'That email doesn’t look valid (or leave it blank).'; renderOverlay(); return; }
  const missingCf = customFieldsFor('customers').find((f) => f.required && !(o.draft.custom[f.id] || '').trim());
  if (missingCf) { o.error = `“${missingCf.label}” is required.`; renderOverlay(); document.querySelector(`.overlay [data-cf="${missingCf.id}"]`)?.focus(); return; }
  if (o.draft.requiresPO !== true && o.draft.requiresPO !== false) { o.error = ''; o.tab = 'account'; renderOverlay(); flashOr('.overlay .js-nc-po', 'Choose PO — Yes or No before saving.'); return; }   // force the PO answer
  const d = o.draft;
  if (o.editId) {                                   // ── editing / completing an existing customer ──
    const c = IDX.customer.get(o.editId); if (!c) { closeOverlay(); return; }
    Object.assign(c, { firstName: d.firstName, lastName: d.lastName, company: d.company, phone: d.phone, email: d.email, industry: d.industry, accountType: d.accountType || 'Non-Business', requiresPO: !!d.requiresPO, accountNotes: d.accountNotes, idNumber: d.idNumber || '', netDays: normNetDays(d.netDays), custom: d.custom || {} });   // §7.1b signature/agreement live on the card
    if (!c.accountNotes) c.accountNotesColor = '';   // popup has no dot picker — don't leave a stale tag on a cleared note
    c.name = `${d.firstName} ${d.lastName}`.trim() || c.name;
    reindex('customers', c);
    commitCapture(o, c);   // Save IS the commit — persist any captured selfie + signature
    logAction(c, 'Account details updated');
    const lt = applyCustomerLink(o, c.customerId) || o.linked;   // quick-add-link → land back on the Quote/invoice
    closeOverlay();
    if (lt) { anchorRecord(lt.card, lt.recId); toast(`${c.name} saved and linked.`); }
    else { anchorRecord('customers', c.customerId); toast(`${c.name} updated.`); }
    return;
  }
  const id = nextCustomerId();                       // ── new customer ──
  const c = {
    customerId: id, firstName: d.firstName, lastName: d.lastName, name: `${d.firstName} ${d.lastName}`.trim(),
    company: d.company, phone: d.phone, email: d.email, address: '',
    industry: d.industry, accountType: d.accountType || 'Non-Business', payStatus: 'New Customer',
    requiresPO: !!d.requiresPO, accountNotes: d.accountNotes, stripeId: '', selfie: d.selfie || '', signature: d.signature || '',
    idNumber: d.idNumber || '', netDays: normNetDays(d.netDays), custom: d.custom || {},
    agreementType: d.agreementType || '', agreementSignedAt: d.agreementSignedAt || '',
    interestedCategoryIds: [], activityLog: [], usedSalesStage: 'N/A', membershipStage: 'N/A',
    _digest: { activePct: 0, totalPaid: 0, visits: 0, years: 0, avgFrequencyDays: 0, firstInvoice: '', lastInvoice: '' },
  };
  DATA.customers.push(c); IDX.customer.set(id, c); reindex('customers', c);
  commitCapture(o, c);   // Save IS the commit — persist any captured selfie + signature
  logAction(c, 'Customer onboarded');
  const lt = applyCustomerLink(o, id);   // quick-add-link → land back on the Quote/invoice
  closeOverlay();
  if (lt) { anchorRecord(lt.card, lt.recId); toast(`${c.name} added and linked.`); }
  else { anchorRecord('customers', id); toast(`${c.name} added.`); }
}
/* ════════════════════════════════════════════════════════════════════════
 * §17 STRIPE / PAYMENTS — card-on-file + invoice charging (client side).
 * Card data is entered ONLY in Stripe's iframe (Card Element) and tokenized in
 * the browser; raw PAN/CVC never touches our code or the backend. The backend
 * owns the money math — the client never sends an amount.
 * ════════════════════════════════════════════════════════════════════════ */
let _stripe = null, _cardElements = null, _cardElement = null;
// The publishable key comes from the backend (Script Property STRIPE_PUBLISHABLE_KEY)
// so the client runs in the SAME mode as the secret. Falls back to config.js (demo).
let _pubKey = null, _pubKeyLoaded = false;
async function ensurePubKey() {
  if (_pubKeyLoaded) return;
  _pubKeyLoaded = true;
  if (typeof backendPassword === 'undefined' || !backendPassword) return;   // demo / no backend → config.js fallback
  try { const r = await backendCall('stripePubKey'); if (r && r.ok && r.pubKey && r.pubKey !== _pubKey) { _pubKey = r.pubKey; _stripe = null; } } catch (e) { /* offline → config.js fallback */ }
}
function getStripe() {
  if (_stripe) return _stripe;
  const pk = _pubKey || CFG.STRIPE_PUBLISHABLE_KEY;
  if (typeof Stripe === 'undefined' || !pk) { toast('Payment library not ready yet — try again in a moment.'); return null; }
  try { _stripe = Stripe(pk); } catch (e) { toast('Could not start the payment library.'); return null; }
  return _stripe;
}
// Only Office/Admin take payments. In #local demo (no role) we still show the UI.
const canMoney = () => !currentRole || currentRole === 'Admin' || currentRole === 'Owner' || currentRole === 'Office';
const brandName = (b) => (b || 'Card').replace(/^./, (m) => m.toUpperCase());
const hasCardOnFile = (c) => customerCards(c).length > 0;
/* §12.1 rapid action entry (Jac 2026-06-12): commit per the R14 mode toggle —
   Record logs straight to the Activity Log; Schedule opens the date popup with
   the typed action as the note. The field clears on the next render. */
function commitAction(custId, text, keepOpen) {
  const c = IDX.customer.get(custId); if (!c) return;
  const v = (text || '').trim();
  if (!v) { if (!keepOpen && state.actOpen) { state.actOpen = null; render(); } return; }
  if ((state.actMode || 'record') === 'schedule') { state.actOpen = null; return openOverlay({ kind: 'schedule', customerId: custId, note: v }); }
  c.activityLog = c.activityLog || [];
  c.activityLog.push({ when: TODAY_ISO, text: v });
  reindex('customers', c);
  if (!keepOpen) state.actOpen = null;
  render();
  if (keepOpen) document.querySelector(`.js-act-in[data-rec="${custId}"]`)?.focus();
}
const cardOneLabel = (k) => k ? `${brandName(k.brand)} ••${k.last4}${k.expMonth ? ` · ${k.expMonth}/${String(k.expYear).slice(-2)}` : ''}${k.nickname ? ` · ${k.nickname}` : ''}` : '';
const cardLabel = (c) => { const k = defaultCard(c); return k ? cardOneLabel(k) : ''; };
function friendlyPayErr(r) {
  const code = (r && r.error) || 'charge-failed';
  return ({
    'no-card-on-file': 'No card on file — add one first.', 'no-stripe-customer': 'No card on file — add one first.',
    'consent-required': 'Capture a selfie + signature first (card authorization).',
    'card_declined': 'The card was declined.', 'expired_card': 'That card is expired.', 'insufficient_funds': 'Insufficient funds.',
    'over-ceiling': 'Amount exceeds the per-charge limit — split it or charge manually.', 'bad-invoice-amount': 'Nothing is due on this invoice.',
    'forbidden': 'Only Office/Admin can take payments.', 'stripe-not-configured': 'Payments aren’t configured on the backend yet.',
    'pm-customer-mismatch': 'That card isn’t linked to this customer.', 'setupintent-invalid': 'Card setup didn’t verify — try again.',
    'amount-mismatch': 'Amount changed during payment — flagged for review.', 'customer-mismatch': 'Payment didn’t match this customer.',
    'nothing-to-refund': 'Nothing has been paid on this invoice.', 'no-charge-to-refund': 'No card charge found to refund.',
    'refund-failed': 'The refund didn’t go through — try again.', 'invoice-refunded': 'This invoice was already refunded.',
    'invoice-integrity': 'This invoice changed since it was locked — unlock, review, and re-lock before charging.',
    'ach-failed': 'The ACH debit was returned (e.g. insufficient funds or closed account) — try another method.',
    'verify-incomplete': 'That code didn’t verify the account yet — double-check the customer’s statement.',
    'verify-failed': 'Verification didn’t go through — re-check the code on the customer’s statement.',
    'missing-verify': 'Enter the verification code from the customer’s statement.',
    'server-error': 'Server error — try again.',
  })[code] || 'Payment failed — try again or use another card.';
}

async function openAddCard(customerId, opts) { await ensurePubKey(); openOverlay({ kind: 'addCard', customerId, returnTo: (opts && opts.returnTo) || '', invoiceId: (opts && opts.invoiceId) || '' }); }
async function openAddBank(customerId, opts) { await ensurePubKey(); openOverlay({ kind: 'addAch', customerId, returnTo: (opts && opts.returnTo) || '', invoiceId: (opts && opts.invoiceId) || '' }); }
async function openVerifyBank(customerId, bankId) { await ensurePubKey(); openOverlay({ kind: 'verifyAch', customerId, bankId }); }
async function openPayInvoice(invoiceId) { await ensurePubKey(); openOverlay({ kind: 'payment', invoiceId, busy: false, error: '' }); }

/* §19 ALLOCATION POPUP — the user splits a payment across the invoice's line
   items (pre-tax). Because the charge total is BUILT from these per-line inputs,
   there is never an "unassigned" partial — every dollar lands on a line. Tax
   rides on top of the taxable lines and the gross is shown before charging. */
function allocSectionHtml(lines, o) {
  const rows = lines.map((L) => `
    <div class="alloc-row">
      <span class="alloc-name" data-tip="${esc(L.label)}">${esc(L.label)}</span>
      <span class="alloc-rem">/ ${money(L.remaining)}${L.taxable ? '' : ' · no tax'}</span>
      <span class="alloc-dollar">$<input class="alloc-in" data-key="${esc(L.key)}" data-taxable="${L.taxable ? '1' : '0'}" data-max="${L.remaining}" type="number" min="0" max="${L.remaining}" step="0.01" value="${(Number(o.alloc[L.key]) || 0).toFixed(2)}" ${o.busy ? 'disabled' : ''}></span>
    </div>`).join('');
  return `<div class="alloc-sec">
    <div class="alloc-head"><span>Apply to line items</span>${lines.length > 1 ? `<button class="add-field anchor js-alloc-auto" data-r="R5b" type="button" ${o.busy ? 'disabled' : ''}>Pay in full</button>` : ''}</div>
    ${rows}
    <div class="alloc-foot"><span class="js-alloc-counter"></span><span class="alloc-charge js-alloc-charge"></span></div>
  </div>`;
}
/* Live, DOM-driven recompute (no re-render → inputs keep focus, like the card
   element). Updates o.alloc, the "balance after" counter, the pre-tax+tax=gross
   read-out, and the Charge button label/enabled state. */
function setupPayAlloc() {
  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const body = document.querySelector('.overlay .popup-body'); if (!body) return;
  const ins = [...body.querySelectorAll('.alloc-in')]; if (!ins.length) return;
  const inv = IDX.invoice.get(o.invoiceId); if (!inv) return;
  const cust = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  const exempt = !!(inv.taxExempt || cust?.salesTaxExempt);
  const recompute = () => {
    const bal = invoiceTotals(inv).balance;
    let taxable = 0, plain = 0;
    ins.forEach((inp) => {
      const max = Number(inp.dataset.max) || 0;
      let v = Number(inp.value); if (!(v >= 0)) v = 0; if (v > max + 0.005) { v = max; inp.value = max.toFixed(2); }
      o.alloc[inp.dataset.key] = v;
      if (inp.dataset.taxable === '1') taxable += v; else plain += v;
    });
    const pre = taxable + plain;
    const tax = exempt ? 0 : Math.round(taxable * TAX_RATE * 100) / 100;   // §10 exact-cent tax (matches invoiceTotals — no whole-dollar overcharge)
    const gross = Math.min(pre + tax, bal);
    const after = Math.max(0, bal - gross);
    const counter = body.querySelector('.js-alloc-counter');
    const charge = body.querySelector('.js-alloc-charge');
    const btn = body.querySelector('.js-charge-invoice');
    if (counter) counter.innerHTML = after <= 0.005 ? `<b style="color:var(--good,#1a9f57)">Pays in full ✓</b>` : `Balance after <b>${money2(after)}</b>`;
    if (charge) charge.innerHTML = pre > 0 ? `${money2(pre)}${tax ? ` + ${money2(tax)} tax` : ''} = <b>${money2(gross)}</b>` : '<span class="muted">nothing assigned</span>';
    if (btn) { btn.disabled = !(gross > 0) || !!o.busy; if (!o.busy) btn.textContent = gross > 0 ? `Charge ${money2(gross)}` : 'Charge'; }
  };
  ins.forEach((inp) => inp.addEventListener('input', recompute));
  const auto = body.querySelector('.js-alloc-auto');
  if (auto) auto.addEventListener('click', () => { ins.forEach((inp) => { inp.value = (Number(inp.dataset.max) || 0).toFixed(2); }); recompute(); });
  recompute();
}
/* Resolve the gross charge + the per-line allocations from o.alloc (pre-tax),
   capped at each line's remaining and the invoice balance. */
function allocCharge(inv, o) {
  const cust = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  const exempt = !!(inv.taxExempt || cust?.salesTaxExempt);
  let taxable = 0, plain = 0; const alloc = {};
  allocLines(inv).forEach((L) => {
    const v = Math.min(Number(o.alloc?.[L.key]) || 0, L.remaining);
    if (v <= 0.005) return;
    alloc[L.key] = v;
    if (L.taxable) taxable += v; else plain += v;
  });
  const tax = exempt ? 0 : Math.round(taxable * TAX_RATE * 100) / 100;   // §10 exact-cent tax — the charged gross must use real cents, not a rounded-up dollar
  const gross = Math.min(taxable + plain + tax, invoiceTotals(inv).balance);
  return { gross, alloc };
}

// Mount the Stripe Card Element into the open addCard overlay (called post-append,
// like setupSignaturePad). Recreated per open; destroyed on close.
function mountCardElement() {
  const stripe = getStripe(); if (!stripe) return;
  const host = document.getElementById('sl-card-element'); if (!host) return;
  destroyCardElement();
  _cardElements = stripe.elements();
  _cardElement = _cardElements.create('card', { hidePostalCode: false, style: { base: { color: '#e8ebf2', fontFamily: 'Geist, system-ui, sans-serif', fontSize: '15px', '::placeholder': { color: '#8a93a6' } }, invalid: { color: '#ff6b6b' } } });
  _cardElement.mount('#sl-card-element');
  _cardElement.on('change', (e) => { const b = document.getElementById('sl-card-error'); if (b) b.textContent = e.error ? e.error.message : ''; });
}
function destroyCardElement() { if (_cardElement) { try { _cardElement.destroy(); } catch (e) {} } _cardElement = null; _cardElements = null; }

// Reject if a promise hasn't settled in `ms` so a STALLED (never-resolving) backend
// round-trip can't leave the save button spinning "Saving…" forever with no error.
// fetch() has no built-in timeout; a hung Apps Script call otherwise never rejects.
// Only wraps human-free server round-trips — never the interactive 3DS confirm step.
function withTimeout(promise, ms, label) {
  let t; const timeout = new Promise((_, rej) => { t = setTimeout(() => { const e = new Error((label || 'Request') + ' timed out'); e.rwTimeout = true; rej(e); }, ms); });
  return Promise.race([promise, timeout]).finally(() => clearTimeout(t));
}

// Save card: SetupIntent (server) → confirmCardSetup (browser) → persist (server).
// DOM-driven (no renderOverlay) so the Card Element isn't wiped mid-entry.
async function saveCardFlow(btn) {
  const o = state.overlay; const sub = !!(o && o.kind === 'newCustomer' && o.cardSub);   // §14 card panel beside the onboarding form
  if (!o || (o.kind !== 'addCard' && !sub)) return;
  const c = IDX.customer.get(sub ? o.editId : o.customerId); if (!c) return;
  const stripe = getStripe(); if (!stripe || !_cardElement) return;
  const errBox = document.getElementById('sl-card-error');
  const setErr = (m) => { if (errBox) errBox.textContent = m || ''; };
  const reset = () => { btn.disabled = false; btn.textContent = 'Save card'; };
  // Surface failures LOUDLY (a toast), not just in the small card-field box, so a
  // backend/Stripe error can't silently look like "nothing happened".
  const fail = (m) => { setErr(m); toast('Card not saved — ' + (m || 'try again.')); reset(); };
  // §7.1b a card saves UNSIGNED — the signature/selfie are captured per-card AFTER
  // saving (the signing tab), so DON'T gate the save on a customer-level signature.
  const live = () => state.overlay === o;   // bail if the overlay changed/closed mid-await
  btn.disabled = true; btn.textContent = 'Saving…'; setErr('');
  try {
    const r = await withTimeout(backendCall('stripeSetupIntent', { customerId: c.customerId }), 30000, 'Setting up the card');
    if (!live()) return;
    if (!r || !r.ok) return fail(friendlyPayErr(r));
    const { setupIntent, error } = await stripe.confirmCardSetup(r.clientSecret, { payment_method: { card: _cardElement, billing_details: { name: c.name || undefined, email: c.email || undefined, phone: c.phone || undefined } } });
    if (!live()) return;
    if (error) return fail(error.message);
    if (!setupIntent || setupIntent.status !== 'succeeded') return fail('Card could not be saved — try again.');
    const s = await withTimeout(backendCall('stripeSaveCard', { customerId: c.customerId, paymentMethodId: setupIntent.payment_method, setupIntentId: setupIntent.id }), 30000, 'Saving the card');
    if (!live()) return;
    if (!s || !s.ok) return fail(friendlyPayErr(s));
    c.stripeId = r.stripeId || c.stripeId;
    if (!Array.isArray(c.cards)) c.cards = [];
    const firstCard = customerCards(c).length === 0;
    const sd = o.signDraft, liveCap = !!(sd && sd.selfie && sd.sigData);   // selfie + signature captured in this panel → sign on save
    const held = !!(c.pendingSigning && c.pendingSigning.signature);       // or an account-level agreement already on hand
    const newCardId = 'CARD-' + (state.seq++);
    // §7.1b a card lands UNSIGNED — it can be charged, but the account can't go
    // On Rent / log deliveries until this card is signed for the account type.
    const newCard = { id: newCardId, stripePmId: setupIntent.payment_method, brand: s.card.brand, last4: s.card.last4,
      expMonth: s.card.expMonth, expYear: s.card.expYear, nickname: o.nickname || '', notes: '', isDefault: firstCard, status: 'active',
      agreements: [] };
    c.cards.push(newCard);
    c.cardBrand = s.card.brand; c.cardLast4 = s.card.last4; c.cardExpMonth = s.card.expMonth; c.cardExpYear = s.card.expYear;   // legacy mirror (default card)
    if (liveCap) { signCardAgreement(c, newCard, sd.sigData, sd.selfie); o.signDraft = null; }   // Save IS the commit — sign the card now
    else if (held) attachHeldSigning(c, newCard);   // else a held agreement saddles onto the new card
    const authd = liveCap || held;
    reindex('customers', c); logAction(c, `Card added — ${brandName(s.card.brand)} ••••${s.card.last4}${authd ? '' : ' (unsigned)'}`);
    destroyCardElement();
    toast(authd ? 'Card saved — agreement signed, authorized ✓' : 'Card saved — sign to authorize ✓');
    // Land on the new card's SIGNING tab no matter how Add-card was opened.
    if (sub) { o.cardSub = false; o.tab = newCardId; renderOverlay(); }   // §14 panel beside the form → switch its tab
    else if (o.returnTo === 'payment' && o.invoiceId) openPayInvoice(o.invoiceId);
    else { closeOverlay(); openCustomerForm(c.customerId); if (state.overlay) { state.overlay.tab = newCardId; renderOverlay(); } }   // standalone → open the account form on the signing tab
    render();
  } catch (e) { fail(e && e.rwTimeout ? 'Saving timed out — check your connection and try again.' : 'Network error — try again.'); }
}

// Save ACH: bank SetupIntent (server) → confirmUsBankAccountSetup (browser; raw
// routing/account go straight to Stripe, never to us) → persist (server). Stored
// verified:false until the micro-deposit verification flow ships ("store now, verify
// later", Jac). No Stripe Element — ACH is plain fields handed to Stripe at confirm.
async function saveAchFlow(btn) {
  const o = state.overlay; if (!o || o.kind !== 'addAch') return;
  const c = IDX.customer.get(o.customerId); if (!c) return;
  const stripe = getStripe(); if (!stripe) return;
  const setErr = (m) => { const b = document.getElementById('sl-ach-error'); if (b) b.textContent = m || ''; };
  const reset = () => { btn.disabled = false; btn.textContent = 'Save ACH'; };
  if (!c.signature || !c.selfie) { setErr('Capture a selfie + signature first (ACH authorization).'); return; }
  const holder = (document.getElementById('sl-ach-holder')?.value || '').trim();
  const routing = (document.getElementById('sl-ach-routing')?.value || '').replace(/\D/g, '');
  const account = (document.getElementById('sl-ach-account')?.value || '').replace(/\D/g, '');
  const acctType = document.getElementById('sl-ach-type')?.value || 'checking';
  const holderType = document.getElementById('sl-ach-holdertype')?.value || 'individual';
  if (!holder) return setErr('Enter the account holder name.');
  if (routing.length !== 9) return setErr('Routing number must be 9 digits.');
  if (account.length < 4) return setErr('Enter the account number.');
  const live = () => state.overlay === o;   // bail if the overlay changed/closed mid-await
  btn.disabled = true; btn.textContent = 'Saving…'; setErr('');
  try {
    const r = await backendCall('stripeBankSetupIntent', { customerId: c.customerId });
    if (!live()) return;
    if (!r || !r.ok) { setErr(friendlyPayErr(r)); reset(); return; }
    const { setupIntent, error } = await stripe.confirmUsBankAccountSetup(r.clientSecret, {
      payment_method: { us_bank_account: { routing_number: routing, account_number: account, account_holder_type: holderType, account_type: acctType }, billing_details: { name: holder, email: c.email || undefined } },
    });
    if (!live()) return;
    if (error) { setErr(error.message); reset(); return; }
    if (!setupIntent || !setupIntent.payment_method) { setErr('Bank account could not be saved — try again.'); reset(); return; }
    const s = await backendCall('stripeSaveBank', { customerId: c.customerId, paymentMethodId: setupIntent.payment_method, setupIntentId: setupIntent.id });
    if (!live()) return;
    if (!s || !s.ok) { setErr(friendlyPayErr(s)); reset(); return; }
    c.stripeId = r.stripeId || c.stripeId;
    if (!Array.isArray(c.achAccounts)) c.achAccounts = [];
    const firstBank = customerBanks(c).length === 0;
    const verified = setupIntent.status === 'succeeded';   // microdeposit/instant pending → requires_action → verified:false
    c.achAccounts.push({ id: 'ACH-' + (state.seq++), stripePmId: setupIntent.payment_method, setupIntentId: setupIntent.id, bankName: s.bank.bankName, last4: s.bank.last4,
      accountType: s.bank.accountType || acctType, holder, isDefault: firstBank, verified, status: 'active',
      mandate: { signedAt: TODAY_ISO, version: 'ach', signature: c.signature, selfie: c.selfie } });
    reindex('customers', c); logAction(c, `ACH added — ${s.bank.bankName} ••••${s.bank.last4}${verified ? '' : ' (verification pending)'}`);
    toast(verified ? 'Bank account saved ✓' : 'Bank account saved — verification pending');
    closeOverlay(); render();
  } catch (e) { setErr('Network error — try again.'); reset(); }
}

// §14b verify a pending ACH with the micro-deposit descriptor code (server does the
// Stripe verify_microdeposits call). On success the bank flips to verified → chargeable.
async function verifyAchFlow(btn) {
  const o = state.overlay; if (!o || o.kind !== 'verifyAch') return;
  const c = IDX.customer.get(o.customerId); if (!c) return;
  const k = customerBanks(c).find((x) => x.id === o.bankId); if (!k) return;
  const setErr = (m) => { const b = document.getElementById('sl-vach-error'); if (b) b.textContent = m || ''; };
  const reset = () => { btn.disabled = false; btn.textContent = 'Verify account'; };
  const code = (document.getElementById('sl-vach-code')?.value || '').trim().toUpperCase();
  if (!/^SM[0-9A-Z]{4}$/.test(code)) { setErr('Enter the 6-character code from the statement (starts with SM).'); return; }
  const live = () => state.overlay === o;
  btn.disabled = true; btn.textContent = 'Verifying…'; setErr('');
  try {
    const r = await backendCall('stripeVerifyBank', { customerId: c.customerId, setupIntentId: k.setupIntentId, descriptorCode: code });
    if (!live()) return;
    if (!r || !r.ok) { setErr(friendlyPayErr(r)); reset(); return; }
    k.verified = true;
    reindex('customers', c); logAction(c, `ACH verified — ${k.bankName || 'Bank'} ••••${k.last4}`);
    toast('Bank account verified ✓'); closeOverlay(); render();
  } catch (e) { setErr('Network error — try again.'); reset(); }
}

// §14b reconcile a processing ACH — poll the PaymentIntent. The server settles it
// (records the charge) if it succeeded, or clears it if it bounced. Reuses finalize.
async function checkAchStatus(invoiceId, piId) {
  try {
    const f = await backendCall('stripeFinalizeInvoice', { invoiceId, paymentIntentId: piId });
    if (f && f.ok) { applyPayment(invoiceId, f, null); const inv = IDX.invoice.get(invoiceId); if (inv) delete inv.achProcessing; toast('ACH cleared — payment received ✓'); render(); return; }
    if (f && f.error === 'ach-failed') { const inv = IDX.invoice.get(invoiceId); if (inv) { delete inv.achProcessing; delete inv.pendingPaymentIntentId; } toast('ACH was returned — charge another way.'); render(); return; }
    toast('Still processing — ACH usually settles in 3–5 business days.');
  } catch (e) { toast('Couldn’t check status — try again.'); }
}

// Charge an invoice off_session; on 3DS fall back to an on-session confirm, then
// re-verify server-side before marking paid. The payment overlay has no Card
// Element, so re-rendering it for busy/error states is safe.
async function chargeInvoiceFlow(invoiceId) {
  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const live = () => state.overlay === o;   // bail if the overlay changed/closed mid-await
  // §19: when the allocation rows are present, the gross + per-line split come
  // from o.alloc (pre-tax inputs). Otherwise fall back to the free amount field.
  let amountCents, alloc = null;
  if (o.alloc) {
    const inv0 = IDX.invoice.get(invoiceId); if (!inv0) return;
    const ch = allocCharge(inv0, o); alloc = ch.alloc;
    if (ch.gross <= 0) { o.error = 'Assign an amount to at least one line.'; return renderOverlay(); }
    amountCents = Math.round(ch.gross * 100);
  } else {
    const amtEl = document.querySelector('.overlay .pay-amt-in');
    const dollars = amtEl ? Number(amtEl.value) : NaN;
    amountCents = dollars > 0 ? Math.round(dollars * 100) : null;   // null = full balance; server caps at balance
  }
  o.busy = true; o.error = ''; renderOverlay();
  const fail = (msg) => { if (!live()) return; o.busy = false; o.error = msg; renderOverlay(); };
  const done = (r) => { if (!live()) return; applyPayment(invoiceId, r, alloc); o.alloc = null; o.busy = false; o.error = ''; toast(r.fullyPaid || r.alreadyPaid ? 'Paid in full ✓' : 'Payment captured ✓'); renderOverlay(); };
  try {
    const c = IDX.customer.get(IDX.invoice.get(invoiceId)?.customerId);
    const pick = (o.selectedCardId && (customerCards(c).find((k) => k.id === o.selectedCardId) || verifiedBanks(c).find((k) => k.id === o.selectedCardId))) || defaultCard(c) || verifiedBanks(c)[0];   // §14b card or verified bank
    const r = await backendCall('stripeChargeInvoice', { invoiceId, amountCents, paymentMethodId: pick?.stripePmId || undefined });
    if (!live()) return;
    if (r && r.ok && (r.status === 'succeeded' || r.alreadyPaid)) { done(r); return; }
    if (r && r.ok && r.processing) {   // §14b ACH initiated — NOT paid yet; the invoice shows "processing" until it settles (check status to settle)
      const inv2 = IDX.invoice.get(invoiceId); if (inv2) { inv2.achProcessing = true; if (r.paymentIntentId) inv2.pendingPaymentIntentId = r.paymentIntentId; }
      o.alloc = null; o.busy = false; o.error = ''; toast('ACH payment initiated — it settles in a few business days.'); closeOverlay(); render(); return;
    }
    if (r && r.requiresAction && r.clientSecret) {
      const stripe = getStripe(); if (!stripe) { fail('Payment library not ready.'); return; }
      const { paymentIntent, error } = await stripe.confirmCardPayment(r.clientSecret);
      if (!live()) return;
      if (error) { fail(error.message || 'Authentication failed.'); return; }
      if (paymentIntent && paymentIntent.status === 'succeeded') {
        const f = await backendCall('stripeFinalizeInvoice', { invoiceId, paymentIntentId: r.paymentIntentId });
        if (!live()) return;
        if (f && f.ok) { done(f); return; }
        fail(friendlyPayErr(f)); return;
      }
      fail('Card authentication was not completed.'); return;
    }
    fail(friendlyPayErr(r));
  } catch (e) { fail('Network error — try again.'); }
}
// Refund the captured amount back to the card (full). Reduces amountPaid; a full
// refund flips the invoice to Refunded. The server is authoritative.
async function refundInvoiceFlow(invoiceId) {
  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  // Cash/Check payments (#109) never touched Stripe, so there's no charge to reverse —
  // refund them BY HAND, client-side, exactly as they were recorded (#117). Flip the
  // invoice to Refunded (status derives from inv.refunded) and keep amountPaid so the
  // balance reads $0; release line assignments per the full-refund invariant (§4).
  if (/^cash$/i.test(inv.paymentMethod || '') || /^check/i.test(inv.paymentMethod || '')) {
    // Cash/Check refunds never touched Stripe, but inv.refunded / refundedAmount are
    // server-owned (sync-PROTECTED) — so the SERVER records the manual refund too, else
    // it'd revert on refresh. applyPayment keeps amountPaid (balance reads $0) and flips
    // the status to Refunded. (#109/#117)
    const live = () => state.overlay === o;
    o.busy = true; o.error = ''; o.confirmRefund = false; renderOverlay();
    try {
      const r = await backendCall('recordManualRefund', { invoiceId });
      if (!live()) return;
      if (r && r.ok) { applyPayment(invoiceId, r); o.busy = false; toast('Refunded ✓'); renderOverlay(); return; }
      o.busy = false; o.error = friendlyPayErr(r); renderOverlay(); return;
    } catch (e) { if (live()) { o.busy = false; o.error = 'Network error — try again.'; renderOverlay(); } return; }
  }
  const live = () => state.overlay === o;
  o.busy = true; o.error = ''; o.confirmRefund = false; renderOverlay();
  try {
    const r = await backendCall('stripeRefundInvoice', { invoiceId });
    if (!live()) return;
    if (r && r.ok) { applyPayment(invoiceId, r); o.busy = false; toast('Refunded ✓'); renderOverlay(); return; }
    o.busy = false; o.error = friendlyPayErr(r); renderOverlay();
  } catch (e) { if (live()) { o.busy = false; o.error = 'Network error — try again.'; renderOverlay(); } }
}
// Apply a server charge/refund result to the local invoice; status is derived from amountPaid.
// alloc (§19) = the pre-tax per-line split just charged; accumulate it into inv.allocations.
function applyPayment(invoiceId, r, alloc) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  const before = invoiceTotals(inv).status;
  if (r.amountPaid != null) inv.amountPaid = r.amountPaid;
  if (r.paid != null) inv.paid = r.paid;
  if (r.paidAt) inv.paidAt = r.paidAt;
  if (r.paymentMethod) inv.paymentMethod = r.paymentMethod;
  if (r.refunded != null) inv.refunded = r.refunded;
  if (r.refundedAmount != null) inv.refundedAmount = r.refundedAmount;
  if (r.locked != null) inv.locked = r.locked;
  if (alloc) { inv.allocations = inv.allocations || {}; Object.entries(alloc).forEach(([k, v]) => { inv.allocations[k] = (Number(inv.allocations[k]) || 0) + v; }); }
  if (inv.refunded) inv.allocations = {};   // a full refund releases every line assignment
  reindex('invoices', inv);
  const after = invoiceTotals(inv).status;
  logAction(inv, r.refundedCents != null ? `Refunded ${money((r.refundedCents || 0) / 100)} — ${before} → ${after}` : `Payment — ${before} → ${after} (${r.paymentMethod || 'card'})`);
  render();
}
// Record a manual CASH / CHECK payment (#109) — no Stripe. The figure is captured to
// the exact cent (no ceiling/rounding) and clamped at the outstanding balance so a
// payment can never overpay; partials just dial the amount down. amountPaid persists
// through the normal record sync, exactly like every other invoice field.
// Record a manual CASH / CHECK payment (#109) — no Stripe. The figure is captured to
// the exact cent and clamped at the outstanding balance so a payment can never overpay.
// The SERVER records it (recordManualPayment): invoice money fields (amountPaid,
// paymentMethod, paidAt, payments) are server-owned / sync-PROTECTED, so a client-side
// write gets stripped on sync and "reverts" on refresh (#bug). The backend is
// authoritative — it caps at the live balance, appends to payments[] and audits the
// ledger — exactly like a card charge; we apply its result via applyPayment.
async function recordManualPayment(invoiceId) {
  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  const numEl = document.querySelector('.overlay .js-check-num'); if (numEl) o.checkNum = numEl.value.trim();   // survive the error re-render
  const t = invoiceTotals(inv);
  const amtEl = document.querySelector('.overlay .js-manual-amt');
  const entered = amtEl ? Number(amtEl.value) : NaN;
  if (!(entered > 0)) { o.error = 'Enter an amount greater than $0.'; return renderOverlay(); }
  const balCents = Math.round(t.balance * 100);
  if (balCents <= 0) { o.error = 'Nothing left to pay on this invoice.'; return renderOverlay(); }
  const payCents = Math.min(Math.round(entered * 100), balCents);   // exact cents, never over the balance
  const isCheck = o.method === 'check';
  const checkNum = (o.checkNum || '').trim();
  if (isCheck && !checkNum) { o.error = 'Enter the check number.'; return renderOverlay(); }
  const live = () => state.overlay === o;
  o.busy = true; o.error = ''; renderOverlay();
  try {
    const r = await withTimeout(backendCall('recordManualPayment', { invoiceId, amountCents: payCents, method: isCheck ? 'check' : 'cash', checkNum: isCheck ? checkNum : '' }), 30000, 'Recording the payment');
    if (!live()) return;
    if (!r || !r.ok) { o.busy = false; o.error = friendlyPayErr(r); return renderOverlay(); }
    applyPayment(invoiceId, r);   // server is authoritative (amountPaid / paymentMethod / paidAt)
    o.busy = false; closeOverlay();
    toast(invoiceTotals(inv).balance <= 0.005 ? 'Paid in full ✓' : `${r.paymentMethod || 'Cash'} payment recorded ✓`);
  } catch (e) {
    if (live()) { o.busy = false; o.error = (e && e.rwTimeout) ? 'Timed out — try again.' : 'Network error — try again.'; renderOverlay(); }
  }
}
// Print / PDF a customer-facing invoice (#109) — a clean white document (not the dark
// yard UI) rendered into #print-root; the @media print rules hide everything else and
// the browser's print dialog handles paper or "Save as PDF".
function printInvoice(invoiceId) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  const t = invoiceTotals(inv);
  const cust = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  const rows = (inv.lineItems || []).map((li) => `<tr><td>${esc(li.label)}</td><td class="r">${money2(Number(li.amount) || 0)}</td></tr>`).join('')
    || '<tr><td colspan="2" class="pr-empty">No line items.</td></tr>';
  let host = document.getElementById('print-root');
  if (!host) { host = document.createElement('div'); host.id = 'print-root'; document.body.appendChild(host); }
  host.innerHTML = `
    <div class="pr-doc">
      <div class="pr-head"><div class="pr-brand">${esc(companyName())}</div><div class="pr-sub">${esc(companyTagline())}</div></div>
      <div class="pr-meta">
        <div><span class="pr-k">Invoice</span><span class="pr-v">${esc(inv.invoiceId)}</span></div>
        <div><span class="pr-k">Bill to</span><span class="pr-v">${esc(cust ? cust.name : '—')}</span></div>
        <div><span class="pr-k">Date</span><span class="pr-v">${esc(fmtShortDate(inv.date) || '—')}</span></div>
        <div><span class="pr-k">Due</span><span class="pr-v">${esc(inv.dueDate ? fmtShortDate(inv.dueDate) : '—')}</span></div>
        ${inv.po ? `<div><span class="pr-k">PO</span><span class="pr-v">${esc(inv.po)}</span></div>` : ''}
      </div>
      <table class="pr-lines"><thead><tr><th>Description</th><th class="r">Amount</th></tr></thead><tbody>${rows}</tbody></table>
      <div class="pr-tot">
        <div><span>Subtotal</span><span>${money2(t.subtotal)}</span></div>
        <div><span>Tax${t.exempt ? ' (exempt)' : ` (${(TAX_RATE * 100).toFixed(2)}%)`}</span><span>${t.exempt ? '—' : money2(t.tax)}</span></div>
        <div class="pr-big"><span>Total</span><span>${money2(t.total)}</span></div>
        <div><span>Paid${inv.paymentMethod ? ' · ' + esc(inv.paymentMethod) : ''}</span><span>${money2(t.paid)}</span></div>
        <div class="pr-due"><span>Balance due</span><span>${money2(t.balance)}</span></div>
      </div>
      <div class="pr-foot">Thank you for your business — much obliged. Questions on this ticket? Give the yard a holler.</div>
    </div>`;
  document.body.classList.add('printing');
  const cleanup = () => { document.body.classList.remove('printing'); window.removeEventListener('afterprint', cleanup); };
  window.addEventListener('afterprint', cleanup);
  window.print();
}
// Lock (seal pricing) or unlock an invoice via the backend (Office/Admin).
async function lockInvoiceFlow(invoiceId, lock) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  try {
    const r = await backendCall(lock ? 'stripeLockInvoice' : 'stripeUnlockInvoice', { invoiceId });
    if (r && r.ok) { inv.locked = !!r.locked; reindex('invoices', inv); logAction(inv, r.locked ? 'Pricing locked' : 'Pricing unlocked'); render(); toast(r.locked ? 'Pricing locked 🔒' : 'Unlocked for editing'); }
    else toast(friendlyPayErr(r));
  } catch (e) { toast('Couldn’t reach the backend — try again.'); }
}

